    47→/**
    48→ * Visitor interface to inspect OWL Class Restrictions.
    49→ *
    50→ * <p>This visitor traverses an OWL class hierarchy and collects type-safe restriction information
    51→ * for both object properties and data properties. It implements the Visitor pattern via
    52→ * {@link OWLObjectVisitor} to handle different types of OWL class expressions.
    53→ *
    54→ * <h2>Usage</h2>
    55→ * <pre>{@code
    56→ * OWLClass myClass = ...;
    57→ * OWLOntology ontology = ...;
    58→ * OWLClass owlThing = dataFactory.getOWLThing();
    59→ *
    60→ * SchemaVisitor visitor = new SchemaVisitor(myClass, ontology, owlThing, "", false);
    61→ * myClass.accept(visitor);
    62→ *
    63→ * // Access collected restrictions
    64→ * Map<String, List<RestrictionInfo>> restrictions = visitor.getRestrictions();
    65→ * Set<String> objectProperties = visitor.getObjectPropertyNames();
    66→ * }</pre>
    67→ *
    68→ * <h2>Constructor Parameters</h2>
    69→ * <ul>
    70→ *   <li><b>visitedClass</b>: The OWL class to analyze for restrictions</li>
    71→ *   <li><b>onto</b>: The ontology containing the class and its axioms</li>
    72→ *   <li><b>owlThing</b>: Reference to owl:Thing for filtering (restrictions to owl:Thing are ignored)</li>
    73→ *   <li><b>propertyName</b>: Initial property name context (typically empty "")</li>
    74→ *   <li><b>range</b>: Whether analyzing ranges (typically false for initial call)</li>
    75→ * </ul>
    76→ *
    77→ * <h2>Visitor Traversal Behavior</h2>
    78→ * <p>The visitor recursively processes class hierarchies:
    79→ * <ul>
    80→ *   <li>When visiting a class, all {@link org.semanticweb.owlapi.model.OWLSubClassOfAxiom}s are followed</li>
    81→ *   <li>Cycle detection via {@code processedClasses} prevents infinite recursion in circular hierarchies</li>
    82→ *   <li>Complex class expressions (unions, intersections) are recursively traversed via {@code accept()}</li>
    83→ *   <li>Property restrictions are collected and stored as type-safe {@link RestrictionInfo} objects</li>
    84→ * </ul>
    85→ *
    86→ * <h2>Thread Safety</h2>
    87→ * <p>This class is <b>not thread-safe</b>. Each visitor instance maintains mutable state during
    88→ * traversal and should not be shared between threads or reused for multiple traversals.
    89→ *
    90→ * @see RestrictionInfo
    91→ * @see PropertyNameResolver
    92→ */
    93→public class SchemaVisitor implements OWLObjectVisitor {
    94→
    95→  Logger logger = Logger.getLogger(SchemaVisitor.class.getName());
    96→
    97→  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
    98→  private final Set<OWLClass> processedClasses;
    99→  private final OWLClass cls;
   100→  private final OWLOntology onto;
   101→  String propertyName;
   102→  OWLClass owlThing;
   103→  Boolean range;
   104→
   105→
   106→  // Type-safe storage (private with unmodifiable getters)
   107→  private final Map<String, Set<RestrictionInfo>> restrictions = new HashMap<>();
   108→  private final Multimap<String, OWLClass> objectPropertyRanges = HashMultimap.create();
   109→  private final Multimap<String, OWLDatatype> dataPropertyRanges = HashMultimap.create();
   110→
   111→  // Property name tracking (minimal - just names, not full OWL objects)
   112→  private final Set<String> objectPropertyNames = new HashSet<>();
   113→  private final Set<String> dataPropertyNames = new HashSet<>();
   114→
   115→  /**
   116→   * Creates a new SchemaVisitor to analyze OWL class restrictions.
   117→   *
   118→   * @param visitedClass the OWL class to analyze for restrictions
   119→   * @param onto         the ontology containing the class and its axioms
   120→   * @param owlThing     reference to owl:Thing (restrictions to owl:Thing are ignored as they add
   121→   *                     no information)
   122→   * @param propertyName initial property name context (typically empty "" for top-level analysis)
   123→   * @param range        whether this visitor is analyzing property ranges (typically false for
   124→   *                     initial call)
   125→   */
   126→  public SchemaVisitor(OWLClass visitedClass, OWLOntology onto, OWLClass owlThing,
   127→      String propertyName, Boolean range) {
   128→    processedClasses = new HashSet<>();
   129→    this.cls = visitedClass;
   130→    this.onto = onto;
   131→    this.propertyName = propertyName;
   132→    this.owlThing = owlThing;
   133→    this.range = range;
   134→  }
   135→
   136→  @Override
   137→  public void visit(OWLClass ce) {
   138→    if (!processedClasses.contains(ce)) {
   139→      processedClasses.add(ce);
   140→      for (OWLSubClassOfAxiom ax : onto.getSubClassAxiomsForSubClass(ce)) {
   141→        ax.getSuperClass().accept(this);
   142→      }
   143→    }
   144→  }
   145→
   146→  @Override
   147→  public void visit(OWLObjectSomeValuesFrom ce) {
   148→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   149→    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
   150→      propertyName = cleanName(nameResolver.resolve(property));
   151→      objectPropertyNames.add(propertyName);
   152→      restrictions.computeIfAbsent(propertyName, k -> new LinkedHashSet<>())
   153→          .add(new RestrictionInfo.SomeValuesFrom(ce));
   154→    }
   155→
   156→    if (ce.getFiller() instanceof OWLObjectUnionOf ||
   157→        ce.getFiller() instanceof OWLObjectIntersectionOf ||
   158→        ce.getFiller() instanceof OWLObjectOneOf) {
   159→      ce.getFiller().accept(this);
   160→    } else {
   161→      if (!ce.getFiller().asOWLClass().equals(owlThing)) {
   162→        objectPropertyRanges.put(propertyName, ce.getFiller().asOWLClass());
   163→      } else {
   164→        logger.fine("Ignoring owl:Thing range " + propertyName);
   165→      }
   166→    }
   167→    propertyName = "";
   168→  }
   169→
   170→  @Override
   171→  public void visit(OWLObjectAllValuesFrom ce) {
   172→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   173→    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
   174→      propertyName = cleanName(nameResolver.resolve(property));
   175→      objectPropertyNames.add(propertyName);
   176→      restrictions.computeIfAbsent(propertyName, k -> new LinkedHashSet<>())
   177→          .add(new RestrictionInfo.AllValuesFrom(ce));
   178→    }
   179→
   180→    if (ce.getFiller() instanceof OWLObjectUnionOf
   181→        || ce.getFiller() instanceof OWLObjectIntersectionOf) {
   182→      ce.getFiller().accept(this);
   183→    } else {
   184→      if (!ce.getFiller().asOWLClass().equals(owlThing)) {
   185→        objectPropertyRanges.put(propertyName, ce.getFiller().asOWLClass());
   186→      } else {
   187→        logger.fine("Ignoring owl:Thing range " + propertyName);
   188→      }
   189→    }
   190→    propertyName = "";
   191→  }
   192→
   193→  @Override
   194→  public void visit(OWLObjectUnionOf ce) {
   195→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   196→    setBooleanCombinationObjectProperties(ce, ce.getOperands(),
   197→        ce.getObjectPropertiesInSignature());
   198→  }
   199→
   200→  @Override
   201→  public void visit(OWLObjectIntersectionOf ce) {
   202→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   203→    setBooleanCombinationObjectProperties(ce, ce.getOperands(),
   204→        ce.getObjectPropertiesInSignature());
   205→  }
   206→
   207→  @Override
   208→  public void visit(OWLObjectMinCardinality ce) {
   209→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   210→    setPropertiesWithCardinality(ce);
   211→  }
   212→
   213→  @Override
   214→  public void visit(OWLObjectMaxCardinality ce) {
   215→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   216→    setPropertiesWithCardinality(ce);
   217→  }
   218→
   219→  @Override
   220→  public void visit(OWLObjectExactCardinality ce) {
   221→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   222→    setPropertiesWithCardinality(ce);
   223→  }
   224→
   225→  @Override
   226→  public void visit(OWLObjectComplementOf ce) {
   227→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   228→    if (!propertyName.isEmpty()) {
   229→      ce.getOperand().accept(this);
   230→    }
   231→  }
   232→
   233→  @Override
   234→  public void visit(OWLObjectHasValue ce) {
   235→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   236→    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
   237→      propertyName = cleanName(nameResolver.resolve(property));
   238→      objectPropertyNames.add(propertyName);
   239→    }
   240→    propertyName = "";
   241→  }
   242→
   243→  @Override
   244→  public void visit(OWLObjectOneOf ce) {
   245→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   246→    propertyName = "";
   247→  }
   248→
   249→  @Override
   250→  public void visit(OWLDataAllValuesFrom ce) {
   251→    logger.fine("Analyzed Class: " + this.cls + " with axiom: " + ce);
   252→    for (OWLDataProperty property : ce.getDataPropertiesInSignature()) {
   253→      propertyName = cleanName(nameResolver.resolve(property));
   254→      dataPropertyNames.add(propertyName);
   255→      restrictions.computeIfAbsent(propertyName, k -> new LinkedHashSet<>())
   256→          .add(new RestrictionInfo.DataAllValuesFrom(ce));
   257→    }
   258→
   259→    if (ce.getFiller() instanceof OWLDataUnionOf
   260→        || ce.getFiller() instanceof OWLDataIntersectionOf) {
   261→      ce.getFiller().accept(this);
   262→    } else {
   263→      if (!ce.getFiller().asOWLDatatype().equals(owlThing)) {
   264→        dataPropertyRanges.put(propertyName, ce.getFiller().asOWLDatatype());
   265→      } else {
   266→        logger.fine("Ignoring owl:Thing range " + propertyName);
   267→      }
   268→    }
   269→    propertyName = "";
   270→  }
   271→
   272→  @Override
   273→  public void visit(OWLDataSomeValuesFrom ce) {
   274→    logger.fine("Analyzed Class: " + this.cls + " with axiom: " + ce);
   275→    for (OWLDataProperty property : ce.getDataPropertiesInSignature()) {
   276→      propertyName = cleanName(nameResolver.resolve(property));
   277→      dataPropertyNames.add(propertyName);
   278→      restrictions.computeIfAbsent(propertyName, k -> new LinkedHashSet<>())
   279→          .add(new RestrictionInfo.DataSomeValuesFrom(ce));
   280→    }
   281→
   282→    if (ce.getFiller() instanceof OWLDataUnionOf
   283→        || ce.getFiller() instanceof OWLDataIntersectionOf) {
   284→      ce.getFiller().accept(this);
   285→    } else {
   286→      if (!ce.getFiller().asOWLDatatype().equals(owlThing)) {
   287→        dataPropertyRanges.put(propertyName, ce.getFiller().asOWLDatatype());
   288→      } else {
   289→        logger.fine("Ignoring owl:Thing range " + propertyName);
   290→      }
   291→    }
   292→    propertyName = "";
   293→  }
   294→
   295→  @Override
   296→  public void visit(OWLDataUnionOf ce) {
   297→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   298→    setBooleanCombinationDataProperties(ce, ce.getOperands(), ce.getDataPropertiesInSignature());
   299→  }
   300→
   301→  @Override
   302→  public void visit(OWLDataIntersectionOf ce) {
   303→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   304→    setBooleanCombinationDataProperties(ce, ce.getOperands(), ce.getDataPropertiesInSignature());
   305→  }
   306→
   307→  @Override
   308→  public void visit(OWLDataMinCardinality ce) {
   309→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   310→    setDataPropertiesWithCardinality(ce);
   311→  }
   312→
   313→  @Override
   314→  public void visit(OWLDataMaxCardinality ce) {
   315→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   316→    setDataPropertiesWithCardinality(ce);
   317→  }
   318→
   319→  @Override
   320→  public void visit(OWLDataExactCardinality ce) {
   321→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   322→    setDataPropertiesWithCardinality(ce);
   323→  }
   324→
   325→  @Override
   326→  public void visit(OWLDataOneOf ce) {
   327→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   328→    for (OWLLiteral value : ce.getValues()) {
   329→      // Values are now accessed via DataOneOf.getEnumValues() in mappers
   330→    }
   331→    propertyName = "";
   332→  }
   333→
   334→  @Override
   335→  public void visit(OWLDataComplementOf ce) {
   336→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   337→    propertyName = "";
   338→  }
   339→
   340→  @Override
   341→  public void visit(OWLDataHasValue ce) {
   342→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   343→    for (OWLDataProperty property : ce.getDataPropertiesInSignature()) {
   344→      propertyName = cleanName(nameResolver.resolve(property));
   345→      dataPropertyNames.add(propertyName);
   346→    }
   347→    propertyName = "";
   348→  }
   349→
   350→  private void setPropertiesWithCardinality(OWLObjectCardinalityRestriction ce) {
   351→    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
   352→      propertyName = cleanName(nameResolver.resolve(property));
   353→      objectPropertyNames.add(propertyName);
   354→
   355→      final String propName = propertyName;
   356→      RestrictionInfo.from(ce).ifPresent(info ->
   357→          restrictions.computeIfAbsent(propName, k -> new LinkedHashSet<>()).add(info));
   358→
   359→      if (ce.getFiller().isOWLClass()) {
   360→        objectPropertyRanges.put(propertyName, ce.getFiller().asOWLClass());
   361→      }
   362→    }
   363→    propertyName = "";
   364→  }
   365→
   366→  private void setBooleanCombinationObjectProperties(OWLClassExpression expression,
   367→      Set<OWLClassExpression> ranges,
   368→      Set<OWLObjectProperty> properties) {
   369→    if (propertyName.isEmpty()) {
   370→      for (OWLObjectProperty property : properties) {
   371→        propertyName = cleanName(nameResolver.resolve(property));
   372→        objectPropertyNames.add(propertyName);
   373→        for (OWLClassExpression range : ranges) {
   374→          for (OWLObjectProperty rangeProp : range.getObjectPropertiesInSignature()) {
   375→            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
   376→              range.accept(this);
   377→            }
   378→          }
   379→        }
   380→      }
   381→
   382→      for (OWLDataProperty property : expression.getDataPropertiesInSignature()) {
   383→        propertyName = cleanName(nameResolver.resolve(property));
   384→        dataPropertyNames.add(propertyName);
   385→        for (OWLClassExpression range : ranges) {
   386→          for (OWLDataProperty rangeProp : range.getDataPropertiesInSignature()) {
   387→            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
   388→              range.accept(this);
   389→            }
   390→          }
   391→        }
   392→      }
   393→    } else {
   394→      for (OWLClassExpression range : ranges) {
   395→        Set<OWLClass> rangeClasses = range.getClassesInSignature();
   396→        if (rangeClasses.size() != 1) {
   397→          range.accept(this);
   398→        } else if (!range.asOWLClass().equals(owlThing)) {
   399→          // Range is tracked in objectPropertyRanges via visitor methods
   400→        } else {
   401→          logger.fine("Ignoring owl:Thing range " + propertyName);
   402→        }
   403→      }
   404→    }
   405→    propertyName = "";
   406→  }
   407→
   408→  private void setBooleanCombinationDataProperties(OWLDataRange expression,
   409→      Set<OWLDataRange> ranges,
   410→      Set<OWLDataProperty> properties) {
   411→    if (propertyName.isEmpty()) {
   412→      for (OWLDataProperty property : properties) {
   413→        propertyName = cleanName(nameResolver.resolve(property));
   414→        dataPropertyNames.add(propertyName);
   415→        for (OWLDataRange range : ranges) {
   416→          for (OWLDataProperty rangeProp : range.getDataPropertiesInSignature()) {
   417→            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
   418→              range.accept(this);
   419→            }
   420→          }
   421→        }
   422→      }
   423→
   424→      for (OWLObjectProperty property : expression.getObjectPropertiesInSignature()) {
   425→        propertyName = cleanName(nameResolver.resolve(property));
   426→        objectPropertyNames.add(propertyName);
   427→        for (OWLDataRange range : ranges) {
   428→          for (OWLObjectProperty rangeProp : range.getObjectPropertiesInSignature()) {
   429→            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
   430→              range.accept(this);
   431→            }
   432→          }
   433→        }
   434→      }
   435→    } else {
   436→      for (OWLDataRange range : ranges) {
   437→        Set<OWLDatatype> rangeDatatypes = range.getDatatypesInSignature();
   438→        if (rangeDatatypes.size() != 1) {
   439→          range.accept(this);
   440→        } else if (!range.asOWLDatatype().asOWLClass().equals(owlThing)) {
   441→          // Range is tracked in dataPropertyRanges via visitor methods
   442→        } else {
   443→          logger.fine("Ignoring owl:Thing range " + propertyName);
   444→        }
   445→      }
   446→    }
   447→    propertyName = "";
   448→  }
   449→
   450→  private void setDataPropertiesWithCardinality(OWLDataCardinalityRestriction ce) {
   451→    for (OWLDataProperty property : ce.getDataPropertiesInSignature()) {
   452→      propertyName = cleanName(nameResolver.resolve(property));
   453→      dataPropertyNames.add(propertyName);
   454→
   455→      final String propName = propertyName;
   456→      RestrictionInfo.from(ce).ifPresent(info ->
   457→          restrictions.computeIfAbsent(propName, k -> new LinkedHashSet<>()).add(info));
   458→
   459→      for (OWLDatatype datatype : ce.getDatatypesInSignature()) {
   460→        dataPropertyRanges.put(propertyName, datatype);
   461→      }
   462→    }
   463→    propertyName = "";
   464→  }
   465→
   466→  // Getters for type-safe storage (unmodifiable views)
   467→  public Map<String, Set<RestrictionInfo>> getRestrictions() {
   468→    return Collections.unmodifiableMap(restrictions);
   469→  }
   470→
   471→  public Multimap<String, OWLClass> getObjectPropertyRanges() {
   472→    return Multimaps.unmodifiableMultimap(objectPropertyRanges);
   473→  }
   474→
   475→  public Multimap<String, OWLDatatype> getDataPropertyRanges() {
   476→    return Multimaps.unmodifiableMultimap(dataPropertyRanges);
   477→  }
   478→
   479→  public Set<String> getObjectPropertyNames() {
   480→    return Collections.unmodifiableSet(objectPropertyNames);
   481→  }
   482→
   483→  public Set<String> getDataPropertyNames() {
   484→    return Collections.unmodifiableSet(dataPropertyNames);
   485→  }
   486→
   487→  private static String cleanName(String propertyName) {
   488→    return Objects.requireNonNull(propertyName);
   489→  }
   490→}

