import java.util.Set;

public class TaxonomyPropertyMapper {

  private final String name;
  private final String description;
  private final List<String> ref;

  public boolean isRequired() {
    return isRequired;
  }

  private final boolean isRequired;
  private final boolean isArray;
  private final Set<RestrictionInfo> restrictions;
  private final String label;

  public TaxonomyPropertyMapper(MappingContext context, String propertyName, String description,
      String label, List<String> ref, Set<RestrictionInfo> restrictions) {
    this.name = propertyName;
    this.description = description;
    this.label = label;
    this.ref = ref;
    this.restrictions = restrictions;

    // Compute array and required from restrictions
    YamlConfig config = context.getConfig();
    this.isArray =
        restrictions != null && restrictions.stream().anyMatch(RestrictionInfo::impliesArray);
    this.isRequired = config.isEnforceRequiredness() &&
        restrictions != null && restrictions.stream().anyMatch(RestrictionInfo::impliesRequired);
  }

  public String getName() {
    return name;
  }

  public Schema getTaxonomySchemaObject() {
    return getComposedSchemaObject(this.ref);
  }

  private Schema getComposedSchemaObject(List<String> ref) {
    StringSchema enumSchema = new StringSchema();
    enumSchema.setDescription(this.description);
    enumSchema.setEnum(ref);
    if (isArray) {
      // Is array of enums
      ArraySchema arraySchema = new ArraySchema();
      arraySchema.setName(this.name);
      arraySchema.setTitle(this.label);
      // NEW: Use typed restrictions (Phase 4) - correct OWL semantics
      for (RestrictionInfo restriction : this.restrictions) {
        restriction.applyToArraySchema(arraySchema);
      }
      arraySchema.setItems(enumSchema);
      return arraySchema;
    } else {
      enumSchema.setName(this.name);
      enumSchema.setTitle(this.label);
      // is a single enum
      return enumSchema;
    }
  }
}

