package com.grl;

import static com.grl.component.asg.configuration.Config.load;
import static org.junit.jupiter.api.Assertions.assertTrue;

import com.grl.component.asg.Asg;
import com.grl.component.asg.configuration.YamlConfig;
import com.jayway.jsonpath.DocumentContext;
import com.jayway.jsonpath.JsonPath;
import com.jayway.jsonpath.ReadContext;
import java.io.File;
import java.io.IOException;
import java.io.InputStream;
import java.net.URISyntaxException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.nio.file.StandardCopyOption;
import java.util.HashMap;
import java.util.Map;
import java.util.Objects;
import java.util.Optional;
import org.apache.commons.lang3.StringUtils;

public class TestUtil {

  public static Path copyToRealFile(Class<?> cls, String resourceName) {
    try {

      InputStream is = Optional.ofNullable(cls.getResourceAsStream(resourceName)).orElseThrow();
      Path confFile = Files.createTempFile(StringUtils.substringBeforeLast(resourceName, "."),
          "." + StringUtils.substringAfterLast(resourceName, "."));
      Files.copy(is, confFile, StandardCopyOption.REPLACE_EXISTING);
      return confFile;
    } catch (Exception e) {
      throw new RuntimeException(e);
    }

  }

  public static Path asFilePath(Class<?> cls, String resourceName) {
    try {
      return Paths.get(Objects.requireNonNull(cls.getResource(resourceName)).toURI());
    } catch (URISyntaxException e) {
      throw new RuntimeException(e);
    }
  }


  public static DocumentContext generate(Path configPath) {
    try {
      YamlConfig config = load(configPath);
      File apiSpecFile = config.getApiOutputDir().resolve("openapi.json").toFile();
      if (apiSpecFile.delete()) {
        System.out.println("Deleted existing spec file: " + apiSpecFile);
      }
      Asg.main(new String[]{"-c", configPath.toAbsolutePath().toString()});
      assertTrue(apiSpecFile.exists(),
          "No spec files generated, expected:" + apiSpecFile);
      return JsonPath.parse(apiSpecFile);
    } catch (IOException e) {
      throw new RuntimeException(e);
    }
  }

  private static final Map<Path, ReadContext> generatedSpecs = new HashMap<>();

  public static ReadContext getGeneratedSpec(Path configPath) {
    return generatedSpecs.computeIfAbsent(configPath, TestUtil::generate);
  }
}

