    47→/**
    48→ * Visitor interface to inspect OWL Class Restrictions.
    49→ *
    50→ * <p>This visitor traverses an OWL class hierarchy and collects type-safe restriction information
    51→ * for both object properties and data properties. It implements the Visitor pattern via
    52→ * {@link OWLObjectVisitor} to handle different types of OWL class expressions.
    53→ *
    54→ * <h2>Usage</h2>
    55→ * <pre>{@code
    56→ * OWLClass myClass = ...;
    57→ * OWLOntology ontology = ...;
    58→ * OWLClass owlThing = dataFactory.getOWLThing();
    59→ *
    60→ * SchemaVisitor visitor = new SchemaVisitor(myClass, ontology, owlThing, "", false);
    61→ * myClass.accept(visitor);
    62→ *
    63→ * // Access collected restrictions
    64→ * Map<String, List<RestrictionInfo>> restrictions = visitor.getRestrictions();
    65→ * Set<String> objectProperties = visitor.getObjectPropertyNames();
    66→ * }</pre>
    67→ *
    68→ * <h2>Constructor Parameters</h2>
    69→ * <ul>
    70→ *   <li><b>visitedClass</b>: The OWL class to analyze for restrictions</li>
    71→ *   <li><b>onto</b>: The ontology containing the class and its axioms</li>
    72→ *   <li><b>owlThing</b>: Reference to owl:Thing for filtering (restrictions to owl:Thing are ignored)</li>
    73→ *   <li><b>propertyName</b>: Initial property name context (typically empty "")</li>
    74→ *   <li><b>range</b>: Whether analyzing ranges (typically false for initial call)</li>
    75→ * </ul>
    76→ *
    77→ * <h2>Visitor Traversal Behavior</h2>
    78→ * <p>The visitor recursively processes class hierarchies:
    79→ * <ul>
    80→ *   <li>When visiting a class, all {@link org.semanticweb.owlapi.model.OWLSubClassOfAxiom}s are followed</li>
    81→ *   <li>Cycle detection via {@code processedClasses} prevents infinite recursion in circular hierarchies</li>
    82→ *   <li>Complex class expressions (unions, intersections) are recursively traversed via {@code accept()}</li>
    83→ *   <li>Property restrictions are collected and stored as type-safe {@link RestrictionInfo} objects</li>
    84→ * </ul>
    85→ *
    86→ * <h2>Thread Safety</h2>
    87→ * <p>This class is <b>not thread-safe</b>. Each visitor instance maintains mutable state during
    88→ * traversal and should not be shared between threads or reused for multiple traversals.
    89→ *
    90→ * @see RestrictionInfo
    91→ * @see PropertyNameResolver
    92→ */
    93→public class SchemaVisitor implements OWLObjectVisitor {
    94→
    95→  Logger logger = Logger.getLogger(SchemaVisitor.class.getName());
    96→
    97→  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
    98→  private final Set<OWLClass> processedClasses;
    99→  private final OWLClass cls;
   100→  private final OWLOntology onto;
   101→  String propertyName;
   102→  OWLClass owlThing;
   103→  Boolean range;
   104→
   105→
   106→  // Type-safe storage (private with unmodifiable getters)
   107→  private final Map<String, Set<RestrictionInfo>> restrictions = new HashMap<>();
   108→  private final Multimap<String, OWLClass> objectPropertyRanges = HashMultimap.create();
   109→  private final Multimap<String, OWLDatatype> dataPropertyRanges = HashMultimap.create();
   110→
   111→  // Property name tracking (minimal - just names, not full OWL objects)
   112→  private final Set<String> objectPropertyNames = new HashSet<>();
   113→  private final Set<String> dataPropertyNames = new HashSet<>();
   114→
   115→  /**
   116→   * Creates a new SchemaVisitor to analyze OWL class restrictions.
   117→   *
   118→   * @param visitedClass the OWL class to analyze for restrictions
   119→   * @param onto         the ontology containing the class and its axioms
   120→   * @param owlThing     reference to owl:Thing (restrictions to owl:Thing are ignored as they add
   121→   *                     no information)
   122→   * @param propertyName initial property name context (typically empty "" for top-level analysis)
   123→   * @param range        whether this visitor is analyzing property ranges (typically false for
   124→   *                     initial call)
   125→   */
   126→  public SchemaVisitor(OWLClass visitedClass, OWLOntology onto, OWLClass owlThing,
   127→      String propertyName, Boolean range) {
   128→    processedClasses = new HashSet<>();
   129→    this.cls = visitedClass;
   130→    this.onto = onto;
   131→    this.propertyName = propertyName;
   132→    this.owlThing = owlThing;
   133→    this.range = range;
   134→  }
   135→
   136→  @Override
   137→  public void visit(OWLClass ce) {
   138→    if (!processedClasses.contains(ce)) {
   139→      processedClasses.add(ce);
   140→      for (OWLSubClassOfAxiom ax : onto.getSubClassAxiomsForSubClass(ce)) {
   141→        ax.getSuperClass().accept(this);
   142→      }
   143→    }
   144→  }
   145→
   146→  @Override
   147→  public void visit(OWLObjectSomeValuesFrom ce) {
   148→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   149→    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
   150→      propertyName = cleanName(nameResolver.resolve(property));
   151→      objectPropertyNames.add(propertyName);
   152→      restrictions.computeIfAbsent(propertyName, k -> new LinkedHashSet<>())
   153→          .add(new RestrictionInfo.SomeValuesFrom(ce));
   154→    }
   155→
   156→    if (ce.getFiller() instanceof OWLObjectUnionOf ||
   157→        ce.getFiller() instanceof OWLObjectIntersectionOf ||
   158→        ce.getFiller() instanceof OWLObjectOneOf) {
   159→      ce.getFiller().accept(this);
   160→    } else {
   161→      if (!ce.getFiller().asOWLClass().equals(owlThing)) {
   162→        objectPropertyRanges.put(propertyName, ce.getFiller().asOWLClass());
   163→      } else {
   164→        logger.fine("Ignoring owl:Thing range " + propertyName);
   165→      }
   166→    }
   167→    propertyName = "";
   168→  }
   169→
   170→  @Override
   171→  public void visit(OWLObjectAllValuesFrom ce) {
   172→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   173→    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
   174→      propertyName = cleanName(nameResolver.resolve(property));
   175→      objectPropertyNames.add(propertyName);
   176→      restrictions.computeIfAbsent(propertyName, k -> new LinkedHashSet<>())
   177→          .add(new RestrictionInfo.AllValuesFrom(ce));
   178→    }
   179→
   180→    if (ce.getFiller() instanceof OWLObjectUnionOf
   181→        || ce.getFiller() instanceof OWLObjectIntersectionOf) {
   182→      ce.getFiller().accept(this);
   183→    } else {
   184→      if (!ce.getFiller().asOWLClass().equals(owlThing)) {
   185→        objectPropertyRanges.put(propertyName, ce.getFiller().asOWLClass());
   186→      } else {
   187→        logger.fine("Ignoring owl:Thing range " + propertyName);
   188→      }
   189→    }
   190→    propertyName = "";
   191→  }
   192→
   193→  @Override
   194→  public void visit(OWLObjectUnionOf ce) {
   195→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   196→    setBooleanCombinationObjectProperties(ce, ce.getOperands(),
   197→        ce.getObjectPropertiesInSignature());
   198→  }
   199→
   200→  @Override
   201→  public void visit(OWLObjectIntersectionOf ce) {
   202→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   203→    setBooleanCombinationObjectProperties(ce, ce.getOperands(),
   204→        ce.getObjectPropertiesInSignature());
   205→  }
   206→
   207→  @Override
   208→  public void visit(OWLObjectMinCardinality ce) {
   209→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   210→    setPropertiesWithCardinality(ce);
   211→  }
   212→
   213→  @Override
   214→  public void visit(OWLObjectMaxCardinality ce) {
   215→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   216→    setPropertiesWithCardinality(ce);
   217→  }
   218→
   219→  @Override
   220→  public void visit(OWLObjectExactCardinality ce) {
   221→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   222→    setPropertiesWithCardinality(ce);
   223→  }
   224→
   225→  @Override
   226→  public void visit(OWLObjectComplementOf ce) {
   227→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   228→    if (!propertyName.isEmpty()) {
   229→      ce.getOperand().accept(this);
   230→    }
   231→  }
   232→
   233→  @Override
   234→  public void visit(OWLObjectHasValue ce) {
   235→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   236→    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
   237→      propertyName = cleanName(nameResolver.resolve(property));
   238→      objectPropertyNames.add(propertyName);
   239→    }
   240→    propertyName = "";
   241→  }
   242→
   243→  @Override
   244→  public void visit(OWLObjectOneOf ce) {
   245→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   246→    propertyName = "";
   247→  }
   248→
   249→  @Override
   250→  public void visit(OWLDataAllValuesFrom ce) {
   251→    logger.fine("Analyzed Class: " + this.cls + " with axiom: " + ce);
   252→    for (OWLDataProperty property : ce.getDataPropertiesInSignature()) {
   253→      propertyName = cleanName(nameResolver.resolve(property));
   254→      dataPropertyNames.add(propertyName);
