   256→          .add(new RestrictionInfo.DataAllValuesFrom(ce));
   257→    }
   258→
   259→    if (ce.getFiller() instanceof OWLDataUnionOf
   260→        || ce.getFiller() instanceof OWLDataIntersectionOf) {
   261→      ce.getFiller().accept(this);
   262→    } else {
   263→      if (!ce.getFiller().asOWLDatatype().equals(owlThing)) {
   264→        dataPropertyRanges.put(propertyName, ce.getFiller().asOWLDatatype());
