   266→        logger.fine("Ignoring owl:Thing range " + propertyName);
   267→      }
   268→    }
   269→    propertyName = "";
   270→  }
   271→
   272→  @Override
   273→  public void visit(OWLDataSomeValuesFrom ce) {
   274→    logger.fine("Analyzed Class: " + this.cls + " with axiom: " + ce);
   275→    for (OWLDataProperty property : ce.getDataPropertiesInSignature()) {
   276→      propertyName = cleanName(nameResolver.resolve(property));
   277→      dataPropertyNames.add(propertyName);
   278→      restrictions.computeIfAbsent(propertyName, k -> new LinkedHashSet<>())
   279→          .add(new RestrictionInfo.DataSomeValuesFrom(ce));
   280→    }
   281→
   282→    if (ce.getFiller() instanceof OWLDataUnionOf
   283→        || ce.getFiller() instanceof OWLDataIntersectionOf) {
   284→      ce.getFiller().accept(this);
   285→    } else {
   286→      if (!ce.getFiller().asOWLDatatype().equals(owlThing)) {
