   327→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   328→    for (OWLLiteral value : ce.getValues()) {
   329→      // Values are now accessed via DataOneOf.getEnumValues() in mappers
   330→    }
