    21→import org.semanticweb.owlapi.search.EntitySearcher;
    22→
    23→/**
    24→ * Maps detected taxonomy patterns to OpenAPI schemas.
    25→ *
    26→ * <p>This mapper generates OpenAPI schemas based on the taxonomy patterns detected
    27→ * by SchemaVisitor. Each pattern produces a different schema structure:
    28→ *
    29→ * <ul>
    30→ *   <li><b>Pattern A</b>: Inline StringSchema with enum values</li>
    31→ *   <li><b>Pattern B</b>: StringSchema with enum and x-code-metadata extension</li>
    32→ *   <li><b>Pattern C</b>: $ref to schema with x-extensible and optional x-hierarchy</li>
    33→ *   <li><b>Pattern D</b>: $ref to Coding schema with x-fhir-valueset, x-skos-hierarchy</li>
    34→ * </ul>
    35→ *
    36→ * @see TaxonomyPattern
    37→ * @see TaxonomyInfo
    38→ */
    39→public class TaxonomyPatternMapper {
    40→
    41→  private static final String X_EXTENSIBLE = "x-extensible";
    42→  private static final String X_HIERARCHY = "x-hierarchy";
    43→  private static final String X_CODE_METADATA = "x-code-metadata";
    44→  private static final String X_FHIR_VALUESET = "x-fhir-valueset";
    45→  private static final String X_SKOS_HIERARCHY = "x-skos-hierarchy";
    46→
    47→  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
    48→  private final MappingContext context;
    49→  private final TaxonomyInfo info;
    50→  private final Set<RestrictionInfo> restrictions;
    51→  private final String description;
    52→  private final String label;
    53→
    54→  private final boolean isArray;
    55→  private final boolean isRequired;
    56→
    57→  public TaxonomyPatternMapper(
    58→      MappingContext context,
    59→      TaxonomyInfo info,
    60→      Set<RestrictionInfo> restrictions,
    61→      String description,
    62→      String label) {
    63→    this.context = context;
    64→    this.info = info;
    65→    this.restrictions = restrictions;
    66→    this.description = description;
    67→    this.label = label;
    68→
    69→    YamlConfig config = context.getConfig();
    70→    this.isArray = restrictions != null &&
    71→        restrictions.stream().anyMatch(RestrictionInfo::impliesArray);
    72→    this.isRequired = config.isEnforceRequiredness() &&
    73→        restrictions != null && restrictions.stream().anyMatch(RestrictionInfo::impliesRequired);
    74→  }
    75→
    76→  public String getName() {
    77→    return info.propertyName();
    78→  }
    79→
    80→  public boolean isRequired() {
    81→    return isRequired;
    82→  }
    83→
    84→  /**
    85→   * Generates the OpenAPI schema based on the detected taxonomy pattern.
    86→   */
    87→  public Schema<?> getSchema() {
    88→    return switch (info.pattern()) {
    89→      case PATTERN_A -> mapPatternA();
    90→      case PATTERN_B -> mapPatternB();
    91→      case PATTERN_C -> mapPatternC();
    92→      case PATTERN_D -> mapPatternD();
    93→      case NONE -> throw new IllegalArgumentException(
    94→          "Cannot map NONE pattern to schema for property: " + info.propertyName());
    95→    };
    96→  }
    97→
    98→  /**
    99→   * Pattern A: Inline enumeration with untyped individuals.
   100→   * Generates StringSchema with enum values from individual labels.
   101→   */
   102→  private Schema<?> mapPatternA() {
   103→    List<String> enumValues = info.individuals().stream()
   104→        .map(ind -> OntologyUtil.getTitle(ind, context.getOntology()))
   105→        .toList();
   106→
   107→    StringSchema enumSchema = new StringSchema();
   108→    enumSchema.setDescription(description);
   109→    enumSchema.setEnum(enumValues);
   110→
   111→    return wrapInArrayIfNeeded(enumSchema);
   112→  }
   113→
   114→  /**
   115→   * Pattern B: Typed individuals with metadata.
   116→   * Generates StringSchema with enum and x-code-metadata extension.
   117→   */
   118→  private Schema<?> mapPatternB() {
   119→    List<String> enumValues = new ArrayList<>();
   120→    Map<String, Object> codeMetadata = new LinkedHashMap<>();
   121→
   122→    for (OWLNamedIndividual ind : info.individuals()) {
   123→      String indName = nameResolver.resolve(ind);
   124→      TaxonomyInfo.IndividualMetadata meta = info.metadata().get(indName);
   125→
   126→      // Use codeValue if available, otherwise use label
   127→      String codeValue = meta != null && meta.codeValue() != null
   128→          ? meta.codeValue()
   129→          : OntologyUtil.getTitle(ind, context.getOntology());
   130→      enumValues.add(codeValue);
   131→
   132→      // Build metadata for this code
   133→      if (meta != null && (meta.displayName() != null || meta.definition() != null)) {
   134→        Map<String, String> metaMap = new LinkedHashMap<>();
   135→        if (meta.displayName() != null) {
   136→          metaMap.put("displayName", meta.displayName());
   137→        }
   138→        if (meta.definition() != null) {
   139→          metaMap.put("definition", meta.definition());
   140→        }
   141→        codeMetadata.put(codeValue, metaMap);
   142→      }
   143→    }
   144→
   145→    StringSchema enumSchema = new StringSchema();
   146→    enumSchema.setDescription(description);
   147→    enumSchema.setEnum(enumValues);
   148→
   149→    if (!codeMetadata.isEmpty()) {
   150→      enumSchema.addExtension(X_CODE_METADATA, codeMetadata);
   151→    }
   152→
   153→    return wrapInArrayIfNeeded(enumSchema);
   154→  }
   155→
   156→  /**
   157→   * Pattern C: Class-based taxonomy (extensible).
   158→   * Generates $ref to schema with x-extensible and optional x-hierarchy.
   159→   */
   160→  private Schema<?> mapPatternC() {
   161→    OWLClass targetClass = info.targetClass();
   162→    if (targetClass == null) {
   163→      throw new IllegalStateException("Pattern C requires a target class");
   164→    }
   165→
   166→    String schemaName = nameResolver.resolve(targetClass);
   167→
   168→    // Create or get the taxonomy schema in components/schemas
   169→    createTaxonomySchemaIfNeeded(schemaName, targetClass);
   170→
   171→    // Create reference to the taxonomy schema
   172→    Schema<?> refSchema = new Schema<>();
   173→    refSchema.set$ref("#/components/schemas/" + schemaName);
   174→
   175→    return wrapInArrayIfNeeded(refSchema);
   176→  }
   177→
   178→  /**
   179→   * Pattern D: SKOS taxonomy (FHIR-compatible).
   180→   * Generates $ref to Coding schema with SKOS/FHIR extensions.
   181→   */
   182→  private Schema<?> mapPatternD() {
   183→    OWLClass targetClass = info.targetClass();
   184→    if (targetClass == null) {
   185→      throw new IllegalStateException("Pattern D requires a target class");
   186→    }
   187→
   188→    String schemaName = nameResolver.resolve(targetClass) + "Coding";
   189→
   190→    // Create or get the SKOS Coding schema
   191→    createSkosCodingSchemaIfNeeded(schemaName, targetClass);
   192→
   193→    // Create reference to the Coding schema
   194→    Schema<?> refSchema = new Schema<>();
   195→    refSchema.set$ref("#/components/schemas/" + schemaName);
   196→
   197→    return wrapInArrayIfNeeded(refSchema);
   198→  }
   199→
   200→  private Schema<?> wrapInArrayIfNeeded(Schema<?> itemSchema) {
   201→    if (isArray) {
   202→      ArraySchema arraySchema = new ArraySchema();
   203→      arraySchema.setName(info.propertyName());
   204→      arraySchema.setTitle(label);
   205→
   206→      // Apply cardinality restrictions
   207→      if (restrictions != null) {
   208→        for (RestrictionInfo restriction : restrictions) {
   209→          restriction.applyToArraySchema(arraySchema);
   210→        }
   211→      }
   212→
   213→      arraySchema.setItems(itemSchema);
   214→      return arraySchema;
   215→    } else {
   216→      itemSchema.setName(info.propertyName());
   217→      itemSchema.setTitle(label);
   218→      return itemSchema;
   219→    }
   220→  }
   221→
   222→  /**
   223→   * Creates the taxonomy schema in components/schemas for Pattern C.
   224→   */
   225→  private void createTaxonomySchemaIfNeeded(String schemaName, OWLClass targetClass) {
   226→    Map<String, Schema<?>> schemas = context.getSchemaByRef();
   227→    if (schemas.containsKey(schemaName)) {
   228→      return;
   229→    }
   230→
   231→    OWLOntology ontology = context.getOntology();
   232→
   233→    ObjectSchema taxonomySchema = new ObjectSchema();
   234→    taxonomySchema.setName(schemaName);
   235→    taxonomySchema.setTitle(OntologyUtil.getTitle(targetClass, ontology));
   236→    taxonomySchema.setDescription(OntologyUtil.getDescription(targetClass, ontology));
   237→
   238→    // Add code property with enum values
   239→    List<String> enumValues = info.individuals().stream()
   240→        .map(ind -> {
   241→          // Try to get codeValue annotation, fallback to label
   242→          String codeVal = getCodeValue(ind, ontology);
   243→          return codeVal != null ? codeVal : OntologyUtil.getTitle(ind, ontology);
   244→        })
   245→        .toList();
   246→
   247→    StringSchema codeSchema = new StringSchema();
   248→    codeSchema.setDescription("The code value");
   249→    if (!enumValues.isEmpty()) {
   250→      codeSchema.setEnum(enumValues);
   251→    }
   252→    taxonomySchema.addProperty("code", codeSchema);
   253→
   254→    // Add displayName property
   255→    StringSchema displayNameSchema = new StringSchema();
   256→    displayNameSchema.setDescription("Human-readable display name");
   257→    taxonomySchema.addProperty("displayName", displayNameSchema);
   258→
   259→    // Mark as extensible
   260→    taxonomySchema.addExtension(X_EXTENSIBLE, true);
   261→
   262→    // Add hierarchy if present
   263→    if (info.hasHierarchy()) {
   264→      Map<String, Object> hierarchy = buildClassHierarchy(targetClass, ontology);
   265→      if (!hierarchy.isEmpty()) {
   266→        taxonomySchema.addExtension(X_HIERARCHY, hierarchy);
   267→      }
   268→    }
   269→
   270→    schemas.put(schemaName, taxonomySchema);
   271→  }
   272→
   273→  /**
   274→   * Creates the SKOS Coding schema in components/schemas for Pattern D.
   275→   */
   276→  private void createSkosCodingSchemaIfNeeded(String schemaName, OWLClass targetClass) {
   277→    Map<String, Schema<?>> schemas = context.getSchemaByRef();
   278→    if (schemas.containsKey(schemaName)) {
   279→      return;
   280→    }
   281→
   282→    OWLOntology ontology = context.getOntology();
   283→
   284→    ObjectSchema codingSchema = new ObjectSchema();
   285→    codingSchema.setName(schemaName);
   286→    codingSchema.setTitle(OntologyUtil.getTitle(targetClass, ontology) + " Coding");
   287→    codingSchema.setDescription("SKOS-based coding for " +
   288→        OntologyUtil.getDescription(targetClass, ontology));
   289→
   290→    // Add system property (constant for the CodeSystem)
   291→    StringSchema systemSchema = new StringSchema();
   292→    systemSchema.setDescription("The CodeSystem URL");
   293→    codingSchema.addProperty("system", systemSchema);
   294→
   295→    // Add code property
   296→    StringSchema codeSchema = new StringSchema();
   297→    codeSchema.setDescription("The code value (skos:notation)");
   298→    codingSchema.addProperty("code", codeSchema);
   299→
   300→    // Add display property
   301→    StringSchema displaySchema = new StringSchema();
   302→    displaySchema.setDescription("Human-readable display (skos:prefLabel)");
   303→    codingSchema.addProperty("display", displaySchema);
   304→
   305→    // Add required fields
   306→    codingSchema.addRequiredItem("code");
   307→
   308→    // Add FHIR/SKOS extensions
   309→    info.getConceptScheme().ifPresent(scheme ->
   310→        codingSchema.addExtension(X_FHIR_VALUESET, nameResolver.resolve(scheme.asOWLNamedIndividual())));
   311→
   312→    // Build SKOS hierarchy
   313→    Map<String, Object> skosHierarchy = buildSkosHierarchy(targetClass, ontology);
   314→    if (!skosHierarchy.isEmpty()) {
   315→      codingSchema.addExtension(X_SKOS_HIERARCHY, skosHierarchy);
   316→    }
   317→
   318→    schemas.put(schemaName, codingSchema);
   319→  }
   320→
   321→  private String getCodeValue(OWLNamedIndividual individual, OWLOntology ontology) {
   322→    // Look for codeValue or skos:notation annotation
   323→    return EntitySearcher.getAnnotations(individual, ontology)
   324→        .filter(ann -> {
   325→          String propName = ann.getProperty().getIRI().getShortForm();
   326→          return propName.equals("codeValue") || propName.equals("notation");
   327→        })
   328→        .findFirst()
   329→        .flatMap(ann -> ann.getValue().asLiteral())
   330→        .map(lit -> lit.getLiteral())
   331→        .orElse(null);
   332→  }
   333→
   334→  private Map<String, Object> buildClassHierarchy(OWLClass parentClass, OWLOntology ontology) {
   335→    Map<String, Object> hierarchy = new LinkedHashMap<>();
   336→
   337→    // Find subclasses and their individuals
   338→    ontology.classesInSignature()
   339→        .filter(subCls -> EntitySearcher.getSuperClasses(subCls, ontology)
   340→            .anyMatch(superCls -> superCls.isNamed() && superCls.asOWLClass().equals(parentClass)))
   341→        .forEach(subCls -> {
   342→          String subClassName = nameResolver.resolve(subCls);
   343→          List<String> codes = EntitySearcher.getIndividuals(subCls, ontology)
   344→              .filter(ind -> ind instanceof OWLNamedIndividual)
   345→              .map(ind -> (OWLNamedIndividual) ind)
   346→              .map(ind -> {
   347→                String codeVal = getCodeValue(ind, ontology);
   348→                return codeVal != null ? codeVal : OntologyUtil.getTitle(ind, ontology);
   349→              })
   350→              .toList();
   351→
   352→          if (!codes.isEmpty()) {
   353→            hierarchy.put(subClassName, codes);
   354→          }
   355→        });
   356→
   357→    return hierarchy;
   358→  }
   359→
   360→  private Map<String, Object> buildSkosHierarchy(OWLClass targetClass, OWLOntology ontology) {
   361→    Map<String, Object> hierarchy = new LinkedHashMap<>();
   362→
   363→    // For SKOS, we build hierarchy based on skos:broader/narrower relationships
   364→    // This is a simplified version - full implementation would traverse the SKOS graph
   365→    for (OWLNamedIndividual ind : info.individuals()) {
   366→      String code = getCodeValue(ind, ontology);
   367→      if (code == null) {
   368→        code = OntologyUtil.getTitle(ind, ontology);
   369→      }
   370→
   371→      Map<String, Object> conceptInfo = new LinkedHashMap<>();
   372→
   373→      // Look for broader concepts
   374→      EntitySearcher.getObjectPropertyValues(ind, ontology)
   375→          .filter(entry -> entry.getKey().getIRI().getShortForm().equals("broader"))
   376→          .flatMap(entry -> entry.getValue().stream())
   377→          .filter(broader -> broader instanceof OWLNamedIndividual)
   378→          .map(broader -> (OWLNamedIndividual) broader)
   379→          .findFirst()
   380→          .ifPresent(broader -> {
   381→            String parentCode = getCodeValue(broader, ontology);
   382→            if (parentCode == null) {
   383→              parentCode = OntologyUtil.getTitle(broader, ontology);
   384→            }
   385→            conceptInfo.put("parent", parentCode);
   386→          });
   387→
   388→      // Look for narrower concepts
   389→      List<String> children = EntitySearcher.getObjectPropertyValues(ind, ontology)
   390→          .filter(entry -> entry.getKey().getIRI().getShortForm().equals("narrower"))
   391→          .flatMap(entry -> entry.getValue().stream())
   392→          .filter(narrower -> narrower instanceof OWLNamedIndividual)
   393→          .map(narrower -> (OWLNamedIndividual) narrower)
   394→          .map(narrower -> {
   395→            String childCode = getCodeValue(narrower, ontology);
   396→            return childCode != null ? childCode : OntologyUtil.getTitle(narrower, ontology);
   397→          })
   398→          .toList();
   399→
   400→      if (!children.isEmpty()) {
   401→        conceptInfo.put("children", children);
   402→      }
   403→
   404→      if (!conceptInfo.isEmpty()) {
   405→        hierarchy.put(code, conceptInfo);
   406→      }
   407→    }
   408→
   409→    return hierarchy;
   410→  }
   411→}
