  private final boolean isRequired;

  public TaxonomyPatternMapper(
      MappingContext context,
      TaxonomyInfo info,
      Set<RestrictionInfo> restrictions,
      String description,
      String label) {
    this.context = context;
    this.info = info;
    this.restrictions = restrictions;
    this.description = description;
    this.label = label;

    YamlConfig config = context.getConfig();
    this.isArray = restrictions != null &&
        restrictions.stream().anyMatch(RestrictionInfo::impliesArray);
    this.isRequired = config.isEnforceRequiredness() &&
        restrictions != null && restrictions.stream().anyMatch(RestrictionInfo::impliesRequired);
  }

  public String getName() {
    return info.propertyName();
  }

  public boolean isRequired() {
    return isRequired;
  }

  /**
   * Generates the OpenAPI schema based on the detected taxonomy pattern.
   */
  public Schema<?> getSchema() {
    return switch (info.pattern()) {
      case PATTERN_A -> mapPatternA();
      case PATTERN_B -> mapPatternB();
      case PATTERN_C -> mapPatternC();
      case PATTERN_D -> mapPatternD();
      case NONE -> throw new IllegalArgumentException(
          "Cannot map NONE pattern to schema for property: " + info.propertyName());
    };
  }

  /**
   * Pattern A: Inline enumeration with untyped individuals.
   * Generates StringSchema with enum values from individual labels.
   */
  private Schema<?> mapPatternA() {
    List<String> enumValues = info.individuals().stream()
        .map(ind -> OntologyUtil.getTitle(ind, context.getOntology()))
        .toList();

    StringSchema enumSchema = new StringSchema();
    enumSchema.setDescription(description);
    enumSchema.setEnum(enumValues);

    return wrapInArrayIfNeeded(enumSchema);
  }

  /**
   * Pattern B: Typed individuals with metadata.
   * Generates StringSchema with enum values (uses codeValue if available, otherwise label).
   */
  private Schema<?> mapPatternB() {
    List<String> enumValues = new ArrayList<>();

    for (OWLNamedIndividual ind : info.individuals()) {
      String indName = nameResolver.resolve(ind);
      TaxonomyInfo.IndividualMetadata meta = info.metadata().get(indName);

      // Use codeValue if available, otherwise use label
      String codeValue = meta != null && meta.codeValue() != null
          ? meta.codeValue()
          : OntologyUtil.getTitle(ind, context.getOntology());
      enumValues.add(codeValue);
    }

    StringSchema enumSchema = new StringSchema();
    enumSchema.setDescription(description);
    enumSchema.setEnum(enumValues);

    return wrapInArrayIfNeeded(enumSchema);
  }

  /**
   * Pattern C: Class-based taxonomy (extensible).
   * Generates $ref to schema in components/schemas.
   */
  private Schema<?> mapPatternC() {
    OWLClass targetClass = info.targetClass();
    if (targetClass == null) {
      throw new IllegalStateException("Pattern C requires a target class");
    }

    String schemaName = nameResolver.resolve(targetClass);

    // Create or get the taxonomy schema in components/schemas
    createTaxonomySchemaIfNeeded(schemaName, targetClass);

    // Create reference to the taxonomy schema
    Schema<?> refSchema = new Schema<>();
    refSchema.set$ref("#/components/schemas/" + schemaName);

    return wrapInArrayIfNeeded(refSchema);
  }

  /**
   * Pattern D: SKOS taxonomy (FHIR-compatible).
   * Generates $ref to Coding schema in components/schemas.
   */
  private Schema<?> mapPatternD() {
    OWLClass targetClass = info.targetClass();
    if (targetClass == null) {
      throw new IllegalStateException("Pattern D requires a target class");
    }

    String schemaName = nameResolver.resolve(targetClass) + "Coding";

    // Create or get the SKOS Coding schema
    createSkosCodingSchemaIfNeeded(schemaName, targetClass);

    // Create reference to the Coding schema
    Schema<?> refSchema = new Schema<>();
    refSchema.set$ref("#/components/schemas/" + schemaName);

    return wrapInArrayIfNeeded(refSchema);
  }

  private Schema<?> wrapInArrayIfNeeded(Schema<?> itemSchema) {
    if (isArray) {
      ArraySchema arraySchema = new ArraySchema();
      arraySchema.setName(info.propertyName());
      arraySchema.setTitle(label);

      // Apply cardinality restrictions
      if (restrictions != null) {
        for (RestrictionInfo restriction : restrictions) {
          restriction.applyToArraySchema(arraySchema);
        }
      }

      arraySchema.setItems(itemSchema);
      return arraySchema;
    } else {
      itemSchema.setName(info.propertyName());
      itemSchema.setTitle(label);
      return itemSchema;
    }
  }

  /**
   * Creates the taxonomy schema in components/schemas for Pattern C.
   */
  private void createTaxonomySchemaIfNeeded(String schemaName, OWLClass targetClass) {
    Map<String, Schema<?>> schemas = context.getSchemaByRef();
    if (schemas.containsKey(schemaName)) {
      return;
    }

    OWLOntology ontology = context.getOntology();

    ObjectSchema taxonomySchema = new ObjectSchema();
    taxonomySchema.setName(schemaName);
    taxonomySchema.setTitle(OntologyUtil.getTitle(targetClass, ontology));
    taxonomySchema.setDescription(OntologyUtil.getDescription(targetClass, ontology));

    // Add code property with enum values
    List<String> enumValues = info.individuals().stream()
        .map(ind -> {
          // Try to get codeValue annotation, fallback to label
          String codeVal = getCodeValue(ind, ontology);
          return codeVal != null ? codeVal : OntologyUtil.getTitle(ind, ontology);
        })
        .toList();

    StringSchema codeSchema = new StringSchema();
    codeSchema.setDescription("The code value");
    if (!enumValues.isEmpty()) {
      codeSchema.setEnum(enumValues);
    }
    taxonomySchema.addProperty("code", codeSchema);

    // Add displayName property
    StringSchema displayNameSchema = new StringSchema();
    displayNameSchema.setDescription("Human-readable display name");
    taxonomySchema.addProperty("displayName", displayNameSchema);

    schemas.put(schemaName, taxonomySchema);
  }

  /**
   * Creates the SKOS Coding schema in components/schemas for Pattern D.
   */
  private void createSkosCodingSchemaIfNeeded(String schemaName, OWLClass targetClass) {
    Map<String, Schema<?>> schemas = context.getSchemaByRef();
    if (schemas.containsKey(schemaName)) {
      return;
    }

    OWLOntology ontology = context.getOntology();

    ObjectSchema codingSchema = new ObjectSchema();
    codingSchema.setName(schemaName);
    codingSchema.setTitle(OntologyUtil.getTitle(targetClass, ontology) + " Coding");
    codingSchema.setDescription("SKOS-based coding for " +
        OntologyUtil.getDescription(targetClass, ontology));

    // Add system property (constant for the CodeSystem)
    StringSchema systemSchema = new StringSchema();
    systemSchema.setDescription("The CodeSystem URL");
    codingSchema.addProperty("system", systemSchema);

    // Add code property
    StringSchema codeSchema = new StringSchema();
    codeSchema.setDescription("The code value (skos:notation)");
    codingSchema.addProperty("code", codeSchema);

    // Add display property
    StringSchema displaySchema = new StringSchema();
    displaySchema.setDescription("Human-readable display (skos:prefLabel)");
    codingSchema.addProperty("display", displaySchema);

    // Add required fields
    codingSchema.addRequiredItem("code");

    schemas.put(schemaName, codingSchema);
  }

  private String getCodeValue(OWLNamedIndividual individual, OWLOntology ontology) {
    // Look for codeValue or skos:notation annotation
    return EntitySearcher.getAnnotations(individual, ontology)
        .filter(ann -> {
          String propName = ann.getProperty().getIRI().getShortForm();
          return propName.equals("codeValue") || propName.equals("notation");
        })
        .findFirst()
        .flatMap(ann -> ann.getValue().asLiteral())
        .map(lit -> lit.getLiteral())
        .orElse(null);
  }

  private Map<String, Object> buildClassHierarchy(OWLClass parentClass, OWLOntology ontology) {
    Map<String, Object> hierarchy = new LinkedHashMap<>();

    // Find subclasses and their individuals
    ontology.classesInSignature()
        .filter(subCls -> EntitySearcher.getSuperClasses(subCls, ontology)
            .anyMatch(superCls -> superCls.isNamed() && superCls.asOWLClass().equals(parentClass)))
        .forEach(subCls -> {
          String subClassName = nameResolver.resolve(subCls);
          List<String> codes = EntitySearcher.getIndividuals(subCls, ontology)
              .filter(ind -> ind instanceof OWLNamedIndividual)
              .map(ind -> (OWLNamedIndividual) ind)
              .map(ind -> {
                String codeVal = getCodeValue(ind, ontology);
                return codeVal != null ? codeVal : OntologyUtil.getTitle(ind, ontology);
              })
              .toList();

          if (!codes.isEmpty()) {
            hierarchy.put(subClassName, codes);
          }
        });

    return hierarchy;
  }

  private Map<String, Object> buildSkosHierarchy(OWLClass targetClass, OWLOntology ontology) {
    Map<String, Object> hierarchy = new LinkedHashMap<>();

    // For SKOS, we build hierarchy based on skos:broader/narrower relationships
    // This is a simplified version - full implementation would traverse the SKOS graph
    for (OWLNamedIndividual ind : info.individuals()) {
      String code = getCodeValue(ind, ontology);
      if (code == null) {
        code = OntologyUtil.getTitle(ind, ontology);
      }

      Map<String, Object> conceptInfo = new LinkedHashMap<>();

      // Look for broader concepts
      EntitySearcher.getObjectPropertyValues(ind, ontology)
          .filter(entry -> entry.getKey().getIRI().getShortForm().equals("broader"))
          .flatMap(entry -> entry.getValue().stream())
          .filter(broader -> broader instanceof OWLNamedIndividual)
          .map(broader -> (OWLNamedIndividual) broader)
          .findFirst()
          .ifPresent(broader -> {
            String parentCode = getCodeValue(broader, ontology);
            if (parentCode == null) {
              parentCode = OntologyUtil.getTitle(broader, ontology);
            }
            conceptInfo.put("parent", parentCode);
          });

      // Look for narrower concepts
      List<String> children = EntitySearcher.getObjectPropertyValues(ind, ontology)
          .filter(entry -> entry.getKey().getIRI().getShortForm().equals("narrower"))
          .flatMap(entry -> entry.getValue().stream())
          .filter(narrower -> narrower instanceof OWLNamedIndividual)
          .map(narrower -> (OWLNamedIndividual) narrower)
          .map(narrower -> {
            String childCode = getCodeValue(narrower, ontology);
            return childCode != null ? childCode : OntologyUtil.getTitle(narrower, ontology);
          })
          .toList();

      if (!children.isEmpty()) {
        conceptInfo.put("children", children);
      }

      if (!conceptInfo.isEmpty()) {
        hierarchy.put(code, conceptInfo);
      }
    }

    return hierarchy;
  }
}

