    // Add system property (constant for the CodeSystem)
    StringSchema systemSchema = new StringSchema();
    systemSchema.setDescription("The CodeSystem URL");
    codingSchema.addProperty("system", systemSchema);

    // Add code property
    StringSchema codeSchema = new StringSchema();
