package regression.features.properties;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertTrue;

import com.grl.TestUtil;
import com.jayway.jsonpath.ReadContext;
import java.util.List;
import java.util.Map;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;

/**
 * Integration tests for taxonomy pattern detection and mapping.
 * Tests all four taxonomy patterns (A, B, C, D) and their OpenAPI output.
 */
public class TaxonomyPatternsIT {

  private static ReadContext spec;

  @BeforeAll
  static void setup() {
    spec = TestUtil.getGeneratedSpec(
        TestUtil.asFilePath(TaxonomyPatternsIT.class,
            "/regression/configs/config_taxonomy_patterns.yaml"));
  }

  @Test
  void resourceSchemaExists() {
    assertNotNull(spec.read("$.components.schemas.PatternTestResource"));
    assertEquals("object", spec.read("$.components.schemas.PatternTestResource.type"));
    assertEquals("Pattern Test Resource", spec.read("$.components.schemas.PatternTestResource.title"));
  }

  @Nested
  class PatternATests {

    @Test
    void patternACreatesInlineEnum() {
      // Pattern A: hasStatusA should create inline enum from untyped individuals
      assertNotNull(spec.read("$.components.schemas.PatternTestResource.properties.StatusA"));
    }

    @Test
    void patternAIsArrayType() {
      // someValuesFrom generates array
      assertEquals("array",
          spec.read("$.components.schemas.PatternTestResource.properties.StatusA.type"));
    }

    @Test
    void patternAHasEnumValues() {
      // Check enum values from individual labels
      List<String> enumValues = spec.read(
          "$.components.schemas.PatternTestResource.properties.StatusA.items.enum", List.class);
      assertNotNull(enumValues);
      assertTrue(enumValues.contains("Active"), "Should contain 'Active'");
      assertTrue(enumValues.contains("Inactive"), "Should contain 'Inactive'");
      assertTrue(enumValues.contains("Pending"), "Should contain 'Pending'");
    }

    @Test
    void patternAHasMinItems() {
      // someValuesFrom implies at least one
      assertEquals(1, spec.read(
          "$.components.schemas.PatternTestResource.properties.StatusA.minItems", Integer.class));
    }

    @Test
    void patternAIsRequired() {
      List<String> required = spec.read(
          "$.components.schemas.PatternTestResource.required", List.class);
      assertTrue(required.contains("StatusA"), "StatusA should be required");
    }
  }

  @Nested
  class PatternBTests {

    @Test
    void patternBCreatesEnumFromTypedIndividuals() {
      // Pattern B: hasSensorType should create enum from typed individuals
      assertNotNull(spec.read("$.components.schemas.PatternTestResource.properties.SensorType"));
    }

    @Test
    void patternBIsArrayType() {
      assertEquals("array",
          spec.read("$.components.schemas.PatternTestResource.properties.SensorType.type"));
    }

    @Test
    void patternBHasEnumValuesFromCodeValue() {
      // Pattern B uses codeValue annotation if available
      List<String> enumValues = spec.read(
          "$.components.schemas.PatternTestResource.properties.SensorType.items.enum", List.class);
      assertNotNull(enumValues);
      // Should use codeValue: analog, digital, hybrid
      assertTrue(enumValues.contains("analog") || enumValues.contains("Analog"),
          "Should contain analog code value");
      assertTrue(enumValues.contains("digital") || enumValues.contains("Digital"),
          "Should contain digital code value");
      assertTrue(enumValues.contains("hybrid") || enumValues.contains("Hybrid"),
          "Should contain hybrid code value");
    }

    @Test
    void patternBHasMinItems() {
      assertEquals(1, spec.read(
          "$.components.schemas.PatternTestResource.properties.SensorType.minItems", Integer.class));
    }

    @Test
    void patternBIsRequired() {
      List<String> required = spec.read(
          "$.components.schemas.PatternTestResource.required", List.class);
      assertTrue(required.contains("SensorType"), "SensorType should be required");
    }
  }

  @Nested
  class PatternCTests {

    @Test
    void patternCCreatesRefToSchema() {
      // Pattern C: hasEnvironment should create $ref to EnvironmentCode schema
      assertNotNull(spec.read("$.components.schemas.PatternTestResource.properties.Environment"));
    }

    @Test
    void patternCIsArrayType() {
      assertEquals("array",
          spec.read("$.components.schemas.PatternTestResource.properties.Environment.type"));
    }

    @Test
    void patternCHasRefToTaxonomySchema() {
      // Items should $ref to the taxonomy schema
      String ref = spec.read(
          "$.components.schemas.PatternTestResource.properties.Environment.items.$ref");
      assertNotNull(ref, "Should have $ref to taxonomy schema");
      assertTrue(ref.contains("EnvironmentCode"), "Should reference EnvironmentCode schema");
    }

    @Test
    void patternCTaxonomySchemaExists() {
      // The referenced schema should exist in components/schemas
      assertNotNull(spec.read("$.components.schemas.EnvironmentCode"),
          "EnvironmentCode schema should exist");
    }

    @Test
    void patternCTaxonomySchemaHasCodeProperty() {
      // Taxonomy schema should have code property with enum
      assertNotNull(spec.read("$.components.schemas.EnvironmentCode.properties.code"));
      List<String> codeEnums = spec.read(
          "$.components.schemas.EnvironmentCode.properties.code.enum", List.class);
      assertNotNull(codeEnums, "code property should have enum values");
    }

    @Test
    void patternCTaxonomySchemaHasDisplayName() {
      assertNotNull(spec.read("$.components.schemas.EnvironmentCode.properties.displayName"));
    }

    @Test
    void patternCIsRequired() {
      List<String> required = spec.read(
          "$.components.schemas.PatternTestResource.required", List.class);
      assertTrue(required.contains("Environment"), "Environment should be required");
    }
  }

  @Nested
  class PatternDTests {

    @Test
    void patternDCreatesRefToCodingSchema() {
      // Pattern D: hasMeasurementContext should create $ref to Coding schema
      assertNotNull(
          spec.read("$.components.schemas.PatternTestResource.properties.MeasurementContext"));
    }

    @Test
    void patternDIsArrayType() {
      assertEquals("array",
          spec.read("$.components.schemas.PatternTestResource.properties.MeasurementContext.type"));
    }

    @Test
    void patternDHasRefToCodingSchema() {
      // Items should $ref to the Coding schema
      String ref = spec.read(
          "$.components.schemas.PatternTestResource.properties.MeasurementContext.items.$ref");
      assertNotNull(ref, "Should have $ref to Coding schema");
      assertTrue(ref.contains("MeasurementContextCode") || ref.contains("Coding"),
          "Should reference MeasurementContextCode or Coding schema");
    }

    @Test
    void patternDCodingSchemaExists() {
      // The Coding schema should exist
      Map<String, Object> schemas = spec.read("$.components.schemas", Map.class);
      boolean hasCodingSchema = schemas.keySet().stream()
          .anyMatch(name -> name.contains("MeasurementContext"));
      assertTrue(hasCodingSchema, "MeasurementContext-related schema should exist");
    }

    @Test
    void patternDCodingSchemaHasCodeProperty() {
      // Look for the Coding schema and verify it has code property
      Map<String, Object> schemas = spec.read("$.components.schemas", Map.class);
      String codingSchemaName = schemas.keySet().stream()
          .filter(name -> name.contains("MeasurementContext"))
          .findFirst()
          .orElse(null);

      if (codingSchemaName != null) {
        assertNotNull(spec.read("$.components.schemas." + codingSchemaName + ".properties.code"),
            "Coding schema should have code property");
      }
    }

    @Test
    void patternDIsRequired() {
      List<String> required = spec.read(
          "$.components.schemas.PatternTestResource.required", List.class);
      assertTrue(required.contains("MeasurementContext"), "MeasurementContext should be required");
    }
  }

  @Nested
  class EndpointTests {

    @Test
    void resourceHasCollectionEndpoint() {
      assertNotNull(spec.read("$.paths['/PatternTestResource']"));
    }

    @Test
    void resourceHasSingleEndpoint() {
      assertNotNull(spec.read("$.paths['/PatternTestResource/{PatternTestResourceId}']"));
    }
  }
}

