   479→    }
   480→    propertyName = "";
   481→  }
   482→
   483→  // Getters for type-safe storage (unmodifiable views)
   484→  public Map<String, Set<RestrictionInfo>> getRestrictions() {
   485→    return Collections.unmodifiableMap(restrictions);
   486→  }
   487→
   488→  public Multimap<String, OWLClass> getObjectPropertyRanges() {
   489→    return Multimaps.unmodifiableMultimap(objectPropertyRanges);
   490→  }
   491→
   492→  public Multimap<String, OWLDatatype> getDataPropertyRanges() {
   493→    return Multimaps.unmodifiableMultimap(dataPropertyRanges);
   494→  }
   495→
   496→  public Set<String> getObjectPropertyNames() {
   497→    return Collections.unmodifiableSet(objectPropertyNames);
   498→  }
   499→
   500→  public Set<String> getDataPropertyNames() {
   501→    return Collections.unmodifiableSet(dataPropertyNames);
   502→  }
   503→
   504→  public Map<String, TaxonomyInfo> getTaxonomyPatterns() {
   505→    return Collections.unmodifiableMap(taxonomyPatterns);
   506→  }
   507→
   508→  public OWLOntology getOntology() {
   509→    return onto;
   510→  }
   511→
   512→  private static String cleanName(String propertyName) {
   513→    return Objects.requireNonNull(propertyName);
   514→  }
   515→
   516→  /**
   517→   * Detects if a filler class expression represents a taxonomy pattern.
   518→   * Called when processing SomeValuesFrom, AllValuesFrom, or qualified cardinality restrictions.
   519→   */
   520→  private void detectTaxonomyPattern(String propName, OWLClassExpression filler) {
   521→    if (filler instanceof OWLObjectOneOf oneOf) {
   522→      // Pattern A or B: blank node with owl:oneOf
   523→      List<OWLNamedIndividual> individuals = oneOf.individuals()
   524→          .filter(ind -> ind instanceof OWLNamedIndividual)
   525→          .map(ind -> (OWLNamedIndividual) ind)
   526→          .toList();
   527→
   528→      if (!individuals.isEmpty()) {
   529→        boolean hasTypedIndividuals = individuals.stream()
   530→            .anyMatch(ind -> hasDomainClass(ind));
   531→
   532→        if (hasTypedIndividuals) {
   533→          // Pattern B: typed individuals with metadata
   534→          Map<String, TaxonomyInfo.IndividualMetadata> metadata = new HashMap<>();
   535→          for (OWLNamedIndividual ind : individuals) {
   536→            OWLClass domainClass = getDomainClass(ind);
   537→            String codeValue = getAnnotationValue(ind, OntologyConstants.SKOS_NOTATION);
   538→            String displayName = getAnnotationValue(ind, OntologyConstants.SKOS_PREFLABEL);
   539→            String definition = getAnnotationValue(ind, OntologyConstants.SKOS_DEFINITION);
   540→            String indName = nameResolver.resolve(ind);
   541→            metadata.put(indName, new TaxonomyInfo.IndividualMetadata(
   542→                codeValue, displayName, definition, domainClass));
   543→          }
   544→          taxonomyPatterns.put(propName, TaxonomyInfo.patternB(propName, individuals, metadata));
   545→        } else {
   546→          // Pattern A: untyped individuals (inline enum)
   547→          taxonomyPatterns.put(propName, TaxonomyInfo.patternA(propName, individuals));
   548→        }
   549→      }
   550→    } else if (filler.isNamed() && filler instanceof OWLClass targetClass) {
   551→      // Named class - check for Pattern C or D
   552→      if (isSubClassOfSkosConcept(targetClass) || hasInSchemeRestriction(targetClass)) {
   553→        // Pattern D: SKOS taxonomy
   554→        var conceptScheme = findConceptScheme(targetClass);
   555→        var individuals = findSkosConceptIndividuals(targetClass);
   556→        taxonomyPatterns.put(propName, TaxonomyInfo.patternD(
   557→            propName, targetClass, individuals, conceptScheme));
   558→      } else if (!hasObjectPropertyRestrictions(targetClass)) {
   559→        // Pattern C: class-based taxonomy (no object property restrictions)
   560→        var individuals = findClassIndividuals(targetClass);
   561→        boolean hasHierarchy = hasSubclassHierarchy(targetClass);
   562→        taxonomyPatterns.put(propName, TaxonomyInfo.patternC(
   563→            propName, targetClass, individuals, hasHierarchy));
   564→      }
   565→      // else: domain class with object property restrictions - not a taxonomy
   566→    }
   567→  }
   568→
   569→  private boolean hasDomainClass(OWLNamedIndividual individual) {
   570→    return EntitySearcher.getTypes(individual, onto)
   571→        .anyMatch(type -> type.isNamed() && !type.isOWLThing());
   572→  }
   573→
   574→  private OWLClass getDomainClass(OWLNamedIndividual individual) {
   575→    return EntitySearcher.getTypes(individual, onto)
   576→        .filter(type -> type.isNamed() && !type.isOWLThing())
   577→        .map(OWLClassExpression::asOWLClass)
   578→        .findFirst()
   579→        .orElse(null);
   580→  }
   581→
   582→  private String getAnnotationValue(OWLNamedIndividual individual, org.semanticweb.owlapi.model.IRI annotationIRI) {
   583→    return EntitySearcher.getAnnotations(individual, onto)
   584→        .filter(ann -> ann.getProperty().getIRI().equals(annotationIRI))
   585→        .findFirst()
   586→        .flatMap(ann -> ann.getValue().asLiteral())
   587→        .map(lit -> lit.getLiteral())
   588→        .orElse(null);
   589→  }
   590→
   591→  private boolean isSubClassOfSkosConcept(OWLClass cls) {
   592→    return EntitySearcher.getSuperClasses(cls, onto)
   593→        .anyMatch(superCls -> superCls.isNamed() &&
   594→            superCls.asOWLClass().getIRI().equals(OntologyConstants.SKOS_CONCEPT));
   595→  }
   596→
   597→  private boolean hasInSchemeRestriction(OWLClass cls) {
   598→    return onto.subClassAxiomsForSubClass(cls)
   599→        .map(ax -> ax.getSuperClass())
   600→        .anyMatch(superCls -> {
   601→          if (superCls instanceof org.semanticweb.owlapi.model.OWLObjectHasValue hasValue) {
   602→            return hasValue.getProperty().isNamed() &&
   603→                hasValue.getProperty().asOWLObjectProperty().getIRI().equals(OntologyConstants.SKOS_IN_SCHEME);
   604→          }
   605→          return false;
   606→        });
   607→  }
   608→
   609→  private boolean hasObjectPropertyRestrictions(OWLClass cls) {
   610→    return onto.subClassAxiomsForSubClass(cls)
   611→        .map(ax -> ax.getSuperClass())
   612→        .anyMatch(superCls -> !superCls.getObjectPropertiesInSignature().isEmpty());
   613→  }
   614→
   615→  private boolean hasSubclassHierarchy(OWLClass cls) {
   616→    return onto.classesInSignature()
   617→        .anyMatch(subCls -> EntitySearcher.getSuperClasses(subCls, onto)
   618→            .anyMatch(superCls -> superCls.isNamed() && superCls.asOWLClass().equals(cls)));
   619→  }
   620→
   621→  private org.semanticweb.owlapi.model.OWLIndividual findConceptScheme(OWLClass cls) {
   622→    // Look for skos:inScheme restriction value
   623→    return onto.subClassAxiomsForSubClass(cls)
   624→        .map(ax -> ax.getSuperClass())
   625→        .filter(superCls -> superCls instanceof org.semanticweb.owlapi.model.OWLObjectHasValue)
   626→        .map(superCls -> (org.semanticweb.owlapi.model.OWLObjectHasValue) superCls)
   627→        .filter(hasValue -> hasValue.getProperty().isNamed() &&
   628→            hasValue.getProperty().asOWLObjectProperty().getIRI().equals(OntologyConstants.SKOS_IN_SCHEME))
   629→        .map(hasValue -> hasValue.getFiller())
   630→        .findFirst()
   631→        .orElse(null);
   632→  }
   633→
   634→  private List<OWLNamedIndividual> findSkosConceptIndividuals(OWLClass cls) {
   635→    List<OWLNamedIndividual> result = new ArrayList<>();
   636→    // Find individuals that are instances of this class or have skos:inScheme pointing to the same scheme
   637→    EntitySearcher.getIndividuals(cls, onto)
   638→        .filter(ind -> ind instanceof OWLNamedIndividual)
   639→        .map(ind -> (OWLNamedIndividual) ind)
   640→        .forEach(result::add);
   641→    return result;
   642→  }
   643→
   644→  private List<OWLNamedIndividual> findClassIndividuals(OWLClass cls) {
   645→    List<OWLNamedIndividual> result = new ArrayList<>();
   646→    // Find all individuals of this class and its subclasses
   647→    EntitySearcher.getIndividuals(cls, onto)
   648→        .filter(ind -> ind instanceof OWLNamedIndividual)
   649→        .map(ind -> (OWLNamedIndividual) ind)
   650→        .forEach(result::add);
   651→
   652→    // Also check subclasses
   653→    onto.classesInSignature()
   654→        .filter(subCls -> EntitySearcher.getSuperClasses(subCls, onto)
   655→            .anyMatch(superCls -> superCls.isNamed() && superCls.asOWLClass().equals(cls)))
   656→        .forEach(subCls -> EntitySearcher.getIndividuals(subCls, onto)
   657→            .filter(ind -> ind instanceof OWLNamedIndividual)
   658→            .map(ind -> (OWLNamedIndividual) ind)
   659→            .forEach(result::add));
   660→
   661→    return result;
   662→  }
   663→}

