      assertNotNull(spec.read("$.components.schemas.EnvironmentCode"),
          "EnvironmentCode schema should exist");
    }

    @Test
    void patternCTaxonomySchemaHasCodeProperty() {
      // Taxonomy schema should have code property with enum
      assertNotNull(spec.read("$.components.schemas.EnvironmentCode.properties.code"));
      List<String> codeEnums = spec.read(
          "$.components.schemas.EnvironmentCode.properties.code.enum", List.class);
      assertNotNull(codeEnums, "code property should have enum values");
    }

    @Test
    void patternCTaxonomySchemaHasDisplayName() {
      assertNotNull(spec.read("$.components.schemas.EnvironmentCode.properties.displayName"));
    }

    @Test
    void patternCIsRequired() {
      List<String> required = spec.read(
          "$.components.schemas.PatternTestResource.required", List.class);
      assertTrue(required.contains("Environment"), "Environment should be required");
